namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New feature: Dark mode is now available."),
        });
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    /// <summary>
    /// Returns notifications newer than the given ID, simulating a real-time feed.
    /// Occasionally generates a new notification to keep things interesting.
    /// </summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            // ~30% chance of a new notification each poll cycle
            if (Random.Shared.Next(0, 10) < 3)
            {
                var messages = new[]
                {
                    "You have a new follower!",
                    "Someone commented on your post.",
                    "System maintenance scheduled for tonight.",
                    "Your export is ready for download.",
                    "A new version of the app is available.",
                    "Reminder: Team standup in 15 minutes.",
                };
                CreateNotification(messages[Random.Shared.Next(messages.Length)]);
            }

            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();

            return Task.FromResult(newer);
        }
    }

    private Notification CreateNotification(string message)
    {
        var notification = new Notification(_nextId++, message, DateTime.UtcNow);
        _notifications.Add(notification);
        return notification;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@inject PersistentComponentState ApplicationState
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (_notifications.Count > 0)
    {
        <span class="badge bg-primary ms-2">@_notifications.Count</span>
    }
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private PersistingComponentStateSubscription _persistSub;

    protected override async Task OnInitializedAsync()
    {
        // Try to restore state that was persisted during prerender.
        // This avoids a second fetch when the circuit connects.
        _persistSub = ApplicationState.RegisterOnPersisting(PersistNotifications);

        if (ApplicationState.TryTakeFromJson<List<Notification>>(
                nameof(_notifications), out var restored))
        {
            _notifications = restored!;
        }
        else
        {
            _notifications = await NotificationSvc.GetNotificationsAsync();
        }
    }

    private Task PersistNotifications()
    {
        ApplicationState.PersistAsJson(nameof(_notifications), _notifications);
        return Task.CompletedTask;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender never runs during static SSR prerendering —
        // it only fires once the circuit is live and interactive.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastSeenId = _notifications.Count > 0
                    ? _notifications.Max(n => n.Id)
                    : 0;

                var newer = await NotificationSvc.GetNotificationsSinceAsync(lastSeenId);

                if (newer.Count > 0)
                {
                    _notifications.InsertRange(0, newer);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        _persistSub.Dispose();

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

